competitors.source:
() =>
    createValidate(
      RT.string({
        pattern: {source: '^[a-z0-9-]+$', flags: '', mockSamples: ['my-slug', 'abc', 'a-b-c'], message: 'must be a slug'},
      })
    )

{
    build: () => {
      const check = typia.createIs<string & tags.Pattern<'^[a-z0-9-]+$'>>();
      return (v) => check(v);
    },
    buildErrors: () => {
      const val = typia.createValidate<string & tags.Pattern<'^[a-z0-9-]+$'>>();
      return (v) => val(v).success;
    },
  }
